codeExample.code:
// Every Java program starts with a class.
// The class name MUST match the filename (here: Main.java).
public class Main {

    // The main method is the entry point — Java starts here.
    public static void main(String[] args) {

        // System.out.println() prints text and moves to the next line.
        System.out.println("Hello, World!");
        System.out.println("I am learning Java!");

        // You can print numbers directly — no quotes needed.
        System.out.println(2025);

        // Arithmetic is evaluated before printing.
        System.out.println(100 + 200);
    }
}

